arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

var rawData = mlContext.Data.LoadFromTextFile<CustomerCsv>(dataPath, hasHeader: true, separatorChar: ',');
var modelInputs = mlContext.Data.CreateEnumerable<CustomerCsv>(rawData, reuseRowObject: false)
    .Select(c => new ModelInput
    {
        Age = c.Age,
        Income = c.Income,
        Region = c.Region,
        PurchaseHistory = c.PurchaseHistory,
        Label = string.Equals(c.Churned, "Yes", StringComparison.OrdinalIgnoreCase)
    })
    .ToList();

var dataView = mlContext.Data.LoadFromEnumerable(modelInputs);
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

// --- Configure services ---
builder.Services.AddPredictionEnginePool<ModelInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// --- Endpoints ---
app.MapPost("/predict", (PredictionEnginePool<ModelInput, ChurnPrediction> pool, CustomerRequest req) =>
{
    var input = new ModelInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability
    });
});

app.Run();

// --- Data models ---

public class CustomerCsv
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class ModelInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

